static void controller_set_safe_vent_only(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static bool controller_check_sensor_timed_out(const controller_t *controller, uint32_t now_ms)
{
    const uint32_t timeout_ms = CONTROLLER_SENSOR_TIMEOUT_MS;

    if (!controller->has_valid_pressure ||
        (now_ms > controller->last_pressure_ms &&
         (now_ms - controller->last_pressure_ms) >= timeout_ms)) {
        return true;
    }

    if (!controller->has_valid_door ||
        (now_ms > controller->last_door_ms &&
         (now_ms - controller->last_door_ms) >= timeout_ms)) {
        return true;
    }

    return false;
}

static void controller_apply_state(controller_t *controller, bool compressor_on, bool vent_open, controller_state_t state)
{
    controller->compressor_on = compressor_on;
    controller->vent_open = vent_open;
    controller->state = state;
}

void controller_step_controller(controller_t *controller, uint32_t now_ms)
{
    /* Check for sensor timeout */
    if (controller_check_sensor_timed_out(controller, now_ms)) {
        controller_set_safe_vent_only(controller);
        return;
    }

    /* If door is open, always safe vent */
    if (!controller->has_valid_door || !controller->door_closed) {
        controller_set_safe_vent_only(controller);
        return;
    }

    /* Door is closed and sensors are fresh - apply pressure-based logic */
    if (!controller->has_valid_pressure) {
        /* No valid pressure yet, stay in safe vent */
        controller_set_safe_vent_only(controller);
        return;
    }

    const int pressure = controller->last_pressure_kpa;

    if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        /* Pressure too low - pressurize */
        controller_apply_state(controller, true, false, CONTROLLER_STATE_PRESSURIZING);
    } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        /* Pressure too high - relieve */
        controller_apply_state(controller, false, true, CONTROLLER_STATE_RELIEVING);
    } else {
        /* In band - hold previous state/output */
        /* State remains as-is, outputs remain as-is */
        if (controller->state != CONTROLLER_STATE_HOLDING) {
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
