def _get_current_state(self, session, timeout_s=1.0):
     """Read all pending lines and return the current compressor/vent state based on STATE message."""
     lines = session.read_lines(timeout_s=timeout_s)

     # Find the most recent STATE message and extract actuator state from it
     compressor_on = False
     vent_open = True  # default to safe state

     for line in lines:
         if "STATE SAFE_VENT" in line or "STATE RELIEVING" in line:
             compressor_on = False
             vent_open = True
         elif "STATE PRESSURIZING" in line:
             compressor_on = True
             vent_open = False
         elif "STATE HOLDING" in line:
             # Holding keeps previous state - we need to look at the last ACT messages before this STATE
             # Go through lines and find the most recent actuator commands before the HOLDING message
             holding_idx = None
             for i, l in enumerate(lines):
                 if "STATE HOLDING" in l:
                     holding_idx = i
                     break

             if holding_idx is not None:
                 # Look at ACT messages before this line
                 for i in range(holding_idx - 1, -1, -1):
                     if "ACT COMPRESSOR ON" in lines[i]:
                         compressor_on = True
                         break
                     elif "ACT COMPRESSOR OFF" in lines[i]:
                         compressor_on = False
                         break

                 for i in range(holding_idx - 1, -1, -1):
                     if "ACT VENT OPEN" in lines[i]:
                         vent_open = True
                         break
                     elif "ACT VENT CLOSED" in lines[i]:
                         vent_open = False
                         break

     return compressor_on, vent_open, lines

